config_templates.basic_ebgp:
router bgp {local_as}
  bgp router-id {loopback_ip}
  neighbor {peer_ip} remote-as {peer_as}
  neighbor {peer_ip} description {description}
  neighbor {peer_ip} password {md5_password}
  neighbor {peer_ip} update-source Loopback0
  neighbor {peer_ip} ebgp-multihop 2
  address-family ipv4
    neighbor {peer_ip} activate
    neighbor {peer_ip} soft-reconfiguration inbound
    neighbor {peer_ip} prefix-list FILTER-IN in
    neighbor {peer_ip} prefix-list FILTER-OUT out

config_templates.ibgp_with_rr:
router bgp {as_number}
  bgp router-id {router_id}
  bgp cluster-id {cluster_id}
  neighbor {client_ip} remote-as {as_number}
  neighbor {client_ip} route-reflector-client
  neighbor {client_ip} update-source Loopback0

config_templates.basic_ospf:
router ospf {process_id}
  router-id {router_id}
  auto-cost reference-bandwidth 100000
  area 0 authentication message-digest
  passive-interface default
  no passive-interface {active_interfaces}
  network {network} {wildcard} area {area}

config_templates.interface_config:
interface {int}
  ip ospf {process_id} area {area}
  ip ospf network point-to-point
  ip ospf authentication message-digest
  ip ospf message-digest-key 1 md5 {password}
  ip ospf bfd

eigrp.config_template:
router eigrp CAMPUS
  address-family ipv4 unicast autonomous-system {as}
    af-interface {interface}
      authentication mode md5
      authentication key-chain {keychain}
    af-interface default
      passive-interface
    network {network} {wildcard}
    eigrp router-id {router_id}

hsrp.config_template:
interface Vlan{id}
  ip address {primary_ip} {mask}
  standby version 2
  standby {group} ip {virtual_ip}
  standby {group} priority {priority}
  standby {group} preempt delay minimum 60
  standby {group} authentication md5 key-string {key}
  standby {group} track {interface} decrement 50

bgp.config_template:
protocols {
  bgp {
    group {group_name} {
      type {internal|external};
      local-address {loopback_ip};
      neighbor {peer_ip} {
        description {description};
        authentication-key {password};
        import [ {import_policy} ];
        export [ {export_policy} ];
      }
    }
  }
}

ospf.config_template:
protocols {
  ospf {
    reference-bandwidth 100g;
    area {area_id} {
      interface {int} {
        interface-type p2p;
        authentication {
          md5 1 key {password};
        }
        bfd-liveness-detection {
          minimum-interval 300;
          multiplier 3;
        }
      }
    }
  }
}

bgp.config_template:
router bgp {as_number}
  router-id {router_id}
  neighbor {peer_ip} remote-as {peer_as}
  neighbor {peer_ip} description {description}
  neighbor {peer_ip} password {password}
  address-family ipv4
    neighbor {peer_ip} activate
    neighbor {peer_ip} route-map FILTER-IN in
    neighbor {peer_ip} route-map FILTER-OUT out

bgp.evpn_vxlan:
router bgp {as}
  neighbor {spine_ip} remote-as {spine_as}
  neighbor {spine_ip} update-source Loopback0
  address-family evpn
    neighbor {spine_ip} activate
